import re

allowed_urls = re.compile(r"^https://[\w.-]+\.mycompany\.com(?:/.*)?$")

def filter_alerts(alerts):
    return [a for a in alerts if a.get("status") != "closed"]

def dedupe_alerts(alerts):
    seen = set()
    result = []
    for alert in alerts:
        key = (alert.get("id"), alert.get("timestamp"))
        if key not in seen:
            seen.add(key)
            result.append(alert)
    return result

def process_alerts(alerts):
    for alert in alerts:
        print(f"{alert.get('id')}: {alert.get('message')}")

